 } finally {\n            lock.unlock();\n        }\n    }\n\n    /**\n     * The number of threads blocked waiting on memory\n     */\n    public int queued() {\n        lock.lock();\n        try {\n            return this.waiters.size();\n        } finally {\n            lock.unlock();\n        }\n    }\n\n    /**\n     * The buffer size that will be retained in the free list after use\n     */\n    public int poolableSize() {\n        return this.poolableSize;\n    }\n\n    /**\n     * The total memory managed by this pool\n     */\n    public long totalMemory() {\n        return this.totalMemory;\n    }\n\n    // package-private method used only for testing\n    Deque<Condition> waiters() {\n        return this.waiters;\n    }\n\n    /**\n     * Closes the buffer pool. Memory will be prevented from being allocated, but may be deallocated. All allocations\n     * awaiting available memory will be notified to abort.\n     */\n    public void close() {\n        this.lock.lock();\n        this.closed = true;\n        try {\n            for (Condition waiter : this.waiters)\n                waiter.signal();\n        } finally {\n            this.lock.unlock();\n        }\n    }\n}\n", "numLines": 357, "startLine": 1, "totalLines": 357}}

