   323→    public Deque<ProducerBatch> split(int splitBatchSize) {
   324→        RecordBatch recordBatch = validateAndGetRecordBatch();
   325→        Deque<ProducerBatch> batches = splitRecordsIntoBatches(recordBatch, splitBatchSize);
   326→        finalizeSplitBatches(batches);
   327→        return batches;
   328→    }
   329→
   330→    private RecordBatch validateAndGetRecordBatch() {
   331→        MemoryRecords memoryRecords = recordsBuilder.build();
   332→        Iterator<MutableRecordBatch> recordBatchIter = memoryRecords.batches().iterator();
   333→
   334→        if (!recordBatchIter.hasNext())
   335→            throw new IllegalStateException("Cannot split an empty producer batch.");
   336→
   337→        RecordBatch recordBatch = recordBatchIter.next();
   338→        if (recordBatch.magic() < MAGIC_VALUE_V2 && !recordBatch.isCompressed())
   339→            throw new IllegalArgumentException("Batch splitting cannot be used with non-compressed messages " +
   340→                    "with version v0 and v1");
   341→
   342→        if (recordBatchIter.hasNext())
   343→            throw new IllegalArgumentException("A producer batch should only have one record batch.");
   344→
   345→        return recordBatch;
   346→    }
   347→
   348→    private Deque<ProducerBatch> splitRecordsIntoBatches(RecordBatch recordBatch, int splitBatchSize) {
   349→        Deque<ProducerBatch> batches = new ArrayDeque<>();
   350→        Iterator<Thunk> thunkIter = thunks.iterator();
   351→        // We always allocate batch size because we are already splitting a big batch.
   352→        // And we also Retain the create time of the original batch.
   353→        ProducerBatch batch = null;
   354→
   355→        for (Record record : recordBatch) {
   356→            assert thunkIter.hasNext();
   357→            Thunk thunk = thunkIter.next();
   358→            if (batch == null)
   359→                batch = createBatchOffAccumulatorForRecord(record, splitBatchSize);
   360→
   361→            // A newly created batch can always host the first message.
   362→            if (!batch.tryAppendForSplit(record.timestamp(), record.key(), record.value(), record.headers(), thunk)) {
   363→                batches.add(batch);
   364→                batch.closeForRecordAppends();
   365→                batch = createBatchOffAccumulatorForRecord(record, splitBatchSize);
   366→                batch.tryAppendForSplit(record.timestamp(), record.key(), record.value(), record.headers(), thunk);
   367→            }
   368→        }
   369→
   370→        // Close the last batch and add it to the batch list after split.
   371→        if (batch != null) {
   372→            batches.add(batch);
   373→            batch.closeForRecordAppends();
   374→        }
   375→
   376→        return batches;
   377→    }
   378→
   379→    private void finalizeSplitBatches(Deque<ProducerBatch> batches) {
   380→        // Chain all split batch ProduceRequestResults to the original batch's produceFuture
   381→        // Ensures the original batch's future doesn't complete until all split batches complete
   382→        for (ProducerBatch splitBatch : batches) {
   383→            produceFuture.addDependent(splitBatch.produceFuture);
   384→        }
   385→
   386→        produceFuture.set(ProduceResponse.INVALID_OFFSET, NO_TIMESTAMP, index -> new RecordBatchTooLargeException());
   387→        produceFuture.done();
   388→
   389→        assignProducerStateToBatches(batches);
   390→    }
   391→
   392→    private void assignProducerStateToBatches(Deque<ProducerBatch> batches) {
   393→        if (hasSequence()) {
   394→            int sequence = baseSequence();
   395→            ProducerIdAndEpoch producerIdAndEpoch = new ProducerIdAndEpoch(producerId(), producerEpoch());
   396→            for (ProducerBatch newBatch : batches) {
   397→                newBatch.setProducerState(producerIdAndEpoch, sequence, isTransactional());
   398→                sequence += newBatch.recordCount;
   399→            }
   400→        }
   401→    }
